/* CSS Entrances Classes mapping to Animate.css */
.animate__fadeInUp {
  animation-name: fadeInUp;
}
.animate__slideInRight {
  animation-name: slideInRight;
}

js:
// JS Entrances Trigger Logic
function triggerEntrance(aniName) {
  const el = document.getElementById('preview-box');
  el.className = 'preview-object';
  void el.offsetWidth; // Reflow
  el.classList.add('animate__animated', `animate__${aniName}`);
}
